// Extract proxyWallet addresses from leaderboard and store in workflow static data
const leaders = $input.all();
const staticData = $getWorkflowStaticData('global');

if (!staticData.trackedWallets) {
  staticData.trackedWallets = {};
}

const wallets = [];
for (const item of leaders) {
  const addr = item.json.proxyWallet;
  if (!addr) continue;

  // Store wallet info for reference
  staticData.trackedWallets[addr] = {
    userName: item.json.userName || 'Unknown',
    rank: item.json.rank || 0,
    pnl: item.json.pnl || 0,
    volume: item.json.volume || 0,
    lastSeen: new Date().toISOString()
  };

  wallets.push({
    json: {
      walletAddress: addr,
      userName: item.json.userName || 'Unknown',
      rank: item.json.rank || 0,
      pnl: item.json.pnl || 0
    }
  });
}

return wallets;

// Filter trades from last 5 minutes and calculate mirror position size
const POSITION_SIZE_PCT = 0.10; // Mirror 10% of whale's position size

const trades = $input.all();
const fiveMinAgo = Date.now() - (5 * 60 * 1000);
const mirrorTrades = [];

for (const item of trades) {
  const t = item.json;
  const tradeTime = new Date(t.timestamp || t.createdAt || 0).getTime();

  if (tradeTime > fiveMinAgo) {
    const whaleSize = Number(t.size || t.amount || 0);
    const mirrorSize = Math.max(1, Math.round(whaleSize * POSITION_SIZE_PCT));
    const side = (t.side || 'BUY').toUpperCase();
    const price = Number(t.price || 0);
    const tokenId = t.tokenId || t.asset || '';
    const market = t.market || t.question || t.conditionId || 'Unknown';
    const userName = t.userName || 'Whale';

    mirrorTrades.push({
      json: {
        tokenId,
        side,
        price: price.toFixed(2),
        whaleSize: whaleSize.toFixed(2),
        mirrorSize: mirrorSize.toString(),
        market,
        userName,
        timestamp: t.timestamp || t.createdAt,
        alertMessage: `Copy Trade: ${userName} ${side === 'BUY' ? 'bought' : 'sold'} ${market}\nWhale size: ${whaleSize} | Your size: ${mirrorSize} (${POSITION_SIZE_PCT * 100}%)\nPrice: $${price.toFixed(2)} | Token: ${tokenId}`
      }
    });
  }
}

if (mirrorTrades.length === 0) {
  return [{ json: { _skip: true } }];
}

return mirrorTrades;
